<script setup>
import {ref} from 'vue';import{Head,Link}from'@inertiajs/vue3';import axios from'axios';
const props=defineProps({participations:Array,requests:Array});const items=ref([...props.requests]);const participationId=ref(props.participations?.[0]?.id||'');const type=ref('access_export');const details=ref('');const submit=async()=>{const r=await axios.post(route('participant-portal.data-requests.store'),{project_person_id:participationId.value,type:type.value,request_details:details.value||null});items.value.unshift(r.data.request);details.value='';};const labels={access_export:'Datenauskunft / Export',correction:'Berichtigung',deletion:'Löschanfrage'};const statuses={submitted:'Eingereicht',approved:'Freigegeben',rejected:'Abgelehnt',completed:'Abgeschlossen'};
</script>
<template><Head title="Datenauskunft"/><main class="min-h-screen bg-sky-50 px-5 py-8"><div class="mx-auto max-w-5xl space-y-6"><header class="flex justify-between"><div><p class="text-xs font-semibold uppercase tracking-widest text-zbb">Matrix Teilnehmerportal</p><h1 class="text-2xl font-bold">Meine Daten und Anfragen</h1></div><Link :href="route('participant-portal.dashboard')" class="rounded border bg-white px-4 py-2">Dashboard</Link></header><section class="rounded-2xl border bg-white p-6 shadow"><h2 class="font-semibold">Neue Anfrage</h2><p class="mt-1 text-sm text-gray-500">Eine Lösch- oder Berichtigungsanfrage verändert Daten niemals automatisch. Das Projektteam prüft Identität, Aufbewahrungspflichten und Berechtigung.</p><div class="mt-4 grid gap-3 md:grid-cols-2"><select v-model="participationId" class="rounded border-gray-300"><option v-for="p in participations" :key="p.id" :value="p.id">{{ p.projekt.name }}</option></select><select v-model="type" class="rounded border-gray-300"><option v-for="(label,key) in labels" :key="key" :value="key">{{ label }}</option></select><textarea v-model="details" maxlength="5000" rows="3" placeholder="Erläuterung (bei Berichtigung/Löschung erforderlich)" class="rounded border-gray-300 md:col-span-2"></textarea></div><button class="mt-4 rounded bg-zbb px-4 py-2 text-white" @click="submit">Anfrage einreichen</button></section><section class="rounded-2xl border bg-white p-6 shadow"><h2 class="font-semibold">Meine Anfragen</h2><div class="mt-4 space-y-3"><article v-for="item in items" :key="item.id" class="rounded-xl border p-4"><div class="flex flex-wrap justify-between gap-3"><div><p class="font-semibold">{{ labels[item.type] }}</p><p class="text-xs text-gray-500">{{ item.participation?.projekt?.name }} · {{ new Date(item.created_at).toLocaleString('de-DE') }}</p></div><span class="rounded-full bg-gray-100 px-3 py-1 text-xs">{{ statuses[item.status] }}</span></div><p v-if="item.request_details" class="mt-2 text-sm text-gray-600">{{ item.request_details }}</p><p v-if="item.resolution_note" class="mt-2 rounded bg-gray-50 p-2 text-sm">Antwort: {{ item.resolution_note }}</p><a v-if="item.type==='access_export'&&['approved','completed'].includes(item.status)" :href="route('participant-portal.data-requests.download',item.id)" class="mt-3 inline-block rounded bg-green-600 px-4 py-2 text-sm text-white">Eigene Daten herunterladen</a></article><p v-if="!items.length" class="text-sm text-gray-500">Noch keine Anfragen.</p></div></section></div></main></template>
